/bin/zsh -lc "node --input-type=module -e '
import { withDb } from \"./src/db.mjs\";
import { ensureSchema } from \"./src/schema.mjs\";
import { createAccounts, getAccounts, updateAccounts, deleteAccounts } from \"./src/accounts.mjs\";

await withDb(async (client) => {
  await ensureSchema(client);
  const constraint = await client.query(
    \"SELECT pg_get_constraintdef(oid) AS definition FROM pg_constraint WHERE conrelid = "'$1::regclass AND conname = $2",
    ["accounts", "accounts_risk_score_valid"],
  );
  if (constraint.rowCount !== 1 || !constraint.rows[0].definition.includes("riskScore")) throw new Error("riskScore constraint is missing");

  const id = "acct-risk-boundary-check";
  await deleteAccounts(client, id);
  await createAccounts(client, { accountId: id, name: "Boundary", riskScore: 0 });
  if ((await getAccounts(client, id)).riskScore !== 0) throw new Error("create/get did not preserve riskScore");
  if ((await updateAccounts(client, id, { riskScore: 100 })).riskScore !== 100) throw new Error("update did not preserve riskScore");
  await deleteAccounts(client, id);

  let invalidInputRejected = false;
  try {
    await createAccounts(client, { accountId: id, name: "Invalid", riskScore: 101 });
  } catch (error) {
    invalidInputRejected = error instanceof TypeError;
  }
  if (!invalidInputRejected) throw new Error("application validation accepted riskScore=101");

  let invalidDatabaseRejected = false;
  try {
    await client.query(
      "INSERT INTO accounts (account_id, doc) VALUES ($1, $2)",
      [id, JSON.stringify({ accountId: id, name: "Invalid", riskScore: 101 })],
    );
  } catch (error) {
    invalidDatabaseRejected = error.code === "23514";
  }
  if (!invalidDatabaseRejected) throw new Error("database constraint accepted riskScore=101");
});

console.log("riskScore boundary and schema checks passed");
